/**
 * Priority-based notification router.
 *
 * Routes notifications to the appropriate channel handler based on priority:
 *   - urgent  → SMS channel
 *   - normal  → email channel
 *   - low     → webhook channel
 *
 * This replaces the previous broadcast approach where all channel handlers
 * received every notification via EventBus subscription. Priority routing
 * ensures each notification is delivered through exactly one channel.
 */

import type { NotificationSendEvent, NotificationPriority } from '../events/event-types.js';
import type { NotificationChannelHandler } from './notification.service.js';
import { Logger } from '../utils/logger.js';

export interface PriorityRouteMap {
  urgent: NotificationChannelHandler;
  normal: NotificationChannelHandler;
  low: NotificationChannelHandler;
}

export class PriorityRouter {
  private logger = new Logger('PriorityRouter');
  private routes: PriorityRouteMap;

  constructor(routes: PriorityRouteMap) {
    this.routes = routes;
  }

  async route(event: NotificationSendEvent): Promise<void> {
    const handler = this.routes[event.priority];
    if (!handler) {
      this.logger.error(`No handler registered for priority: ${event.priority}`);
      throw new Error(`No handler registered for priority: ${event.priority}`);
    }

    this.logger.info(
      `Routing ${event.priority} notification to ${event.recipient} via ${this.channelNameFor(event.priority)}`,
    );

    await handler.handle(event);
  }

  private channelNameFor(priority: NotificationPriority): string {
    switch (priority) {
      case 'urgent':
        return 'SMS';
      case 'normal':
        return 'email';
      case 'low':
        return 'webhook';
    }
  }
}

