/**
 * Send a notification. When a PriorityRouter is configured, routes to the
 * appropriate channel based on priority. Otherwise falls back to broadcasting
 * via EventBus for backward compatibility.
 */
private sendNotification(params: {
  recipient: string;
  subject: string;
  body: string;
  priority?: NotificationPriority;
}): void {
  const priority = params.priority ?? 'normal';
  const notification: Notification = {
    id: generateNotificationId(),
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    sentAt: new Date(),
  };
  this.notifications.push(notification);
  this.logger.info(`Notification sent: ${notification.id} to ${params.recipient} [${priority}]`);

  const event: NotificationSendEvent = {
    type: 'notification:send',
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    priority,
    timestamp: new Date(),
  };

  if (this.priorityRouter) {
    // Route to the appropriate channel handler based on priority
    this.priorityRouter.route(event);
  } else {
    // Legacy broadcast: publish to EventBus so all channel handlers deliver
    this.eventBus.emit(event);
  }
}

