describe('PriorityRouter', () => {
  let eventBus: EventBus;
  let emailHandler: EmailNotificationHandler;
  let smsHandler: SmsNotificationHandler;
  let webhookHandler: WebhookNotificationHandler;
  let router: PriorityRouter;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    resetNotificationIdCounter();
    emailHandler = new EmailNotificationHandler(eventBus);
    smsHandler = new SmsNotificationHandler(eventBus);
    webhookHandler = new WebhookNotificationHandler(eventBus);
    router = new PriorityRouter({
      urgent: smsHandler,
      normal: emailHandler,
      low: webhookHandler,
    });
  });

  it('should route urgent notifications to SMS handler', async () => {
    const event: NotificationSendEvent = {
      type: 'notification:send',
      recipient: '+15551234567',
      subject: 'Urgent Alert',
      body: 'Your order is delayed',
      priority: 'urgent',
      timestamp: new Date(),
    };

    await router.route(event);

    expect(smsHandler.getDeliveredMessages()).toHaveLength(1);
    expect(smsHandler.getDeliveredMessages()[0]?.phoneNumber).toBe('+15551234567');
    expect(emailHandler.getDeliveredEmails()).toHaveLength(0);
    expect(webhookHandler.getDeliveredWebhooks()).toHaveLength(0);
  });

  it('should route normal notifications to email handler', async () => {
    const event: NotificationSendEvent = {
      type: 'notification:send',
      recipient: 'alice@example.com',
      subject: 'Order Confirmation',
      body: 'Your order has been placed',
      priority: 'normal',
      timestamp: new Date(),
    };

    await router.route(event);

    expect(emailHandler.getDeliveredEmails()).toHaveLength(1);
    expect(emailHandler.getDeliveredEmails()[0]?.recipient).toBe('alice@example.com');
    expect(smsHandler.getDeliveredMessages()).toHaveLength(0);
    expect(webhookHandler.getDeliveredWebhooks()).toHaveLength(0);
  });

  it('should route low-priority notifications to webhook handler', async () => {
    const event: NotificationSendEvent = {
      type: 'notification:send',
      recipient: 'system@example.com',
      subject: 'Activity Log',
      body: 'User logged in',
      priority: 'low',
      timestamp: new Date(),
    };

    await router.route(event);

    expect(webhookHandler.getDeliveredWebhooks()).toHaveLength(1);
    expect(webhookHandler.getDeliveredWebhooks()[0]?.payload.recipient).toBe('system@example.com');
    expect(emailHandler.getDeliveredEmails()).toHaveLength(0);
    expect(smsHandler.getDeliveredMessages()).toHaveLength(0);
  });

  it('should route multiple notifications to their correct channels', async () => {
    await router.route({
      type: 'notification:send',
      recipient: '+15551234567',
      subject: 'Urgent',
      body: 'Urgent message',
      priority: 'urgent',
      timestamp: new Date(),
    });
    await router.route({
      type: 'notification:send',
      recipient: 'user@example.com',
      subject: 'Normal',
      body: 'Normal message',
      priority: 'normal',
      timestamp: new Date(),
    });
    await router.route({
      type: 'notification:send',
      recipient: 'webhook@example.com',
      subject: 'Low',
      body: 'Low priority message',
      priority: 'low',
      timestamp: new Date(),
    });

    expect(smsHandler.getDeliveredMessages()).toHaveLength(1);
    expect(emailHandler.getDeliveredEmails()).toHaveLength(1);
    expect(webhookHandler.getDeliveredWebhooks()).toHaveLength(1);
  });
});

describe('NotificationService with PriorityRouter', () => {
  let eventBus: EventBus;
  let emailHandler: EmailNotificationHandler;
  let smsHandler: SmsNotificationHandler;
  let webhookHandler: WebhookNotificationHandler;
  let router: PriorityRouter;
  let service: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    resetNotificationIdCounter();
    emailHandler = new EmailNotificationHandler(eventBus);
    smsHandler = new SmsNotificationHandler(eventBus);
    webhookHandler = new WebhookNotificationHandler(eventBus);
    router = new PriorityRouter({
      urgent: smsHandler,
      normal: emailHandler,
      low: webhookHandler,
    });
    service = new NotificationService(eventBus, router);
  });

  it('should route order confirmations (normal priority) to email', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        ],
        total: 20,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    // Normal priority → email channel
    expect(emailHandler.getDeliveredEmails()).toHaveLength(1);
    expect(emailHandler.getDeliveredEmails()[0]?.recipient).toBe('alice@example.com');
    expect(emailHandler.getDeliveredEmails()[0]?.subject).toContain('Order Confirmation');

    // SMS and webhook should NOT receive this notification via the router
    // (They may still receive via their own EventBus subscriptions, but
    // the router only targets the email handler for normal priority)
    expect(smsHandler.getDeliveredMessages()).toHaveLength(0);
    expect(webhookHandler.getDeliveredWebhooks()).toHaveLength(0);
  });

  it('should route order status changes (urgent priority) to SMS', () => {
    const event: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: 'shipped',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'confirmed',
      newStatus: 'shipped',
      timestamp: new Date(),
    };

    statusChangeCallbacks.notify(event);

    // Urgent priority → SMS channel
    expect(smsHandler.getDeliveredMessages()).toHaveLength(1);
    expect(smsHandler.getDeliveredMessages()[0]?.message).toContain('Order Update');
    expect(smsHandler.getDeliveredMessages()[0]?.message).toContain('shipped');

    // Email and webhook should NOT receive this
    expect(emailHandler.getDeliveredEmails()).toHaveLength(0);
    expect(webhookHandler.getDeliveredWebhooks()).toHaveLength(0);
  });

  it('should still record notifications locally regardless of routing', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(service.getNotificationCount()).toBe(1);
    expect(service.getNotificationsForRecipient('alice@example.com')).toHaveLength(1);
  });
});

